// jennie-gateway-v40.1.js
// Changes from v40:
//   - BUGFIX: Edit Task / Edit Garvis modal now shows the due-date field.
//     Previously edit-meta-row2 (containing priority + date) was hidden for
//     non-attention types, hiding the date along with it. Now the row is
//     always shown; only the priority 1-5 dropdown (attention-specific) is
//     hidden for tasks/garvis.
//
// v40 baseline preserved below.
//
// jennie-gateway-v40.js
// Changes from v39.11:
//   - PATCH 3,4,5: promoteToTask / promoteToAttention / promoteToCare now mark
//     the source capture as processed (PUT processed_at, promoted_to_type,
//     promoted_to_id) instead of hard-deleting it. Original capture is preserved
//     in the database with a traceable link to the created destination item.
//   - GET /capture defaults to active (unprocessed) captures, so the visible
//     Capture list still empties on promote.
//   - Use ?status=processed or ?status=all to query historical/promoted captures.
//
// All v39.11 features preserved.
//
// v39.11 baseline:
//   - Toast system: showToast() and showUndoToast() (bottom-center, thumb-friendly)
//   - 16 standard toasts on save / promote / copy / import / edit actions
//   - 5 undo toasts on destructive actions (delete capture/attention/garvis/task,
//     complete task) — 4-sec window, backend call deferred until window closes
//   - New "→ Care" button on every Capture row (creates Attention with
//     operational_domain: 'People')
//   - Bug fix: homepage Care dropdown was reading parseActionState(it).domain === 'care'
//     (never matched). Now reads it.operational_domain === 'People' so Care actually
//     populates.
//   - All v39.10 features preserved.

const COMPASS = 'https://compass-api.shanepass.workers.dev';
const SCOUT_GPT_URL = 'https://chatgpt.com/g/g-6984201405d08191bfa7c85ed835082d-scout-find-true-north';

// ── PWA ICON PLACEHOLDERS (base64-encoded PNGs) ────────────────────────────────
// Final artwork installed: retro chrome chevron badge (navy enamel, chrome J) at 192/512,
// plus chrome script "Jennie" wordmark for the hero header.
const ICON_192_B64 = '';

const ICON_512_B64 = '';

const WORDMARK_B64 = '';

function b64ToBytes(b64) {
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes;
}

function pngResponse(b64) {
  return new Response(b64ToBytes(b64), {
    headers: {
      'Content-Type': 'image/png',
      'Cache-Control': 'public, max-age=86400',
    },
  });
}

// ── PWA SERVICE WORKER (minimal — required for Chrome install prompt) ──────────
const SW_JS = `
// Jennie service worker — minimal, no caching strategy yet.
// Exists so Chrome on Android shows the "Install app" prompt.
self.addEventListener('install', (event) => {
  self.skipWaiting();
});
self.addEventListener('activate', (event) => {
  event.waitUntil(self.clients.claim());
});
self.addEventListener('fetch', (event) => {
  // Pass-through. No caching. Add caching strategies later if needed.
});
`;

function swResponse() {
  return new Response(SW_JS, {
    headers: {
      'Content-Type': 'application/javascript; charset=utf-8',
      'Cache-Control': 'no-cache',
      'Service-Worker-Allowed': '/',
    },
  });
}

// CORS headers for public Scout endpoints
const SCOUT_CORS = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, Authorization',
  'Access-Control-Max-Age': '86400',
};

function html(body, status = 200) {
  return new Response(body, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });
}

function json(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' },
  });
}

function jsonScout(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json', ...SCOUT_CORS },
  });
}

function isAuthed(request, env) {
  const cookie = request.headers.get('Cookie') || '';
  return cookie.includes(`auth=${env.PASSWORD}`);
}

// ── COMPASS HEADERS ────────────────────────────────────────────────────────────
function compassHeaders(env) {
  const headers = { 'Content-Type': 'application/json' };
  if (env.COMPASS_TOKEN) {
    headers['Authorization'] = 'Bearer ' + env.COMPASS_TOKEN;
  }
  return headers;
}

